proof_block:
// The two `forall` ensures-clauses for each kind of object (proc /
// container / thread / endpoint) name only ONE post-state with their
// trigger (the original ensures use `self.get_proc(p_ptr)` etc., which
// becomes `post1_self_.get_<...>(<k>)` for one copy and
// `post2_self_.get_<...>(<k>)` for the other).  Those triggers are
// disjoint, so z3 never lines the two runs up at the same key.
//
// Repair: for each kind, do an `assert forall ... by { ... }` with an
// EXPLICIT multi-trigger that mentions both runs at the shared key.
// The body re-derives the per-key value of each ensures-clause on each
// side and chains them through `pre_self_.<get>(<k>)`.  Then add the
// non-quantified pinned-field equalities for the modified thread /
// endpoint.  We do NOT try to lift to full-Thread / full-Endpoint
// `=~=` at the modified pointer — only the specific fields named by
// the ensures (and therefore named by `det_*_equal`) are forced.

let ep_ptr: EndpointPtr = pre_self_.get_thread(thread_ptr)
    .endpoint_descriptors@[endpoint_index as int].unwrap();

// --- Scalar / domain equalities on each side, then pairwise ---
assert(post1_self_.page_closure() =~= pre_self_.page_closure());
assert(post2_self_.page_closure() =~= pre_self_.page_closure());
assert(post1_self_.page_closure() =~= post2_self_.page_closure());

assert(post1_self_.proc_dom() =~= pre_self_.proc_dom());
assert(post2_self_.proc_dom() =~= pre_self_.proc_dom());
assert(post1_self_.proc_dom() =~= post2_self_.proc_dom());

assert(post1_self_.endpoint_dom() == pre_self_.endpoint_dom());
assert(post2_self_.endpoint_dom() == pre_self_.endpoint_dom());
assert(post1_self_.endpoint_dom() == post2_self_.endpoint_dom());

assert(post1_self_.container_dom() == pre_self_.container_dom());
assert(post2_self_.container_dom() == pre_self_.container_dom());
assert(post1_self_.container_dom() == post2_self_.container_dom());

assert(post1_self_.thread_dom() == pre_self_.thread_dom());
assert(post2_self_.thread_dom() == pre_self_.thread_dom());
assert(post1_self_.thread_dom() == post2_self_.thread_dom());

// --- Pointwise procs: both posts equal pre at every p_ptr in pre's dom. ---
assert forall|p_ptr: ProcPtr|
    #![trigger post1_self_.get_proc(p_ptr)]
    #![trigger post2_self_.get_proc(p_ptr)]
    pre_self_.proc_dom().contains(p_ptr)
    implies post1_self_.get_proc(p_ptr) =~= post2_self_.get_proc(p_ptr) by {
    assert(post1_self_.get_proc(p_ptr) =~= pre_self_.get_proc(p_ptr));
    assert(post2_self_.get_proc(p_ptr) =~= pre_self_.get_proc(p_ptr));
}

// --- Pointwise containers: both posts equal pre at every c_ptr in pre's dom. ---
assert forall|c_ptr: ContainerPtr|
    #![trigger post1_self_.get_container(c_ptr)]
    #![trigger post2_self_.get_container(c_ptr)]
    pre_self_.container_dom().contains(c_ptr)
    implies post1_self_.get_container(c_ptr) =~= post2_self_.get_container(c_ptr) by {
    assert(post1_self_.get_container(c_ptr) =~= pre_self_.get_container(c_ptr));
    assert(post2_self_.get_container(c_ptr) =~= pre_self_.get_container(c_ptr));
}

// --- Pointwise non-modified threads.  Note the ensures clause uses
// `#![trigger pre_self_.get_thread(t_ptr)]` (the OLD state), so we
// include that trigger as well as the two post-states.
assert forall|t_ptr: ThreadPtr|
    #![trigger pre_self_.get_thread(t_ptr)]
    #![trigger post1_self_.get_thread(t_ptr)]
    #![trigger post2_self_.get_thread(t_ptr)]
    pre_self_.thread_dom().contains(t_ptr) && t_ptr != thread_ptr
    implies post1_self_.get_thread(t_ptr) =~= post2_self_.get_thread(t_ptr) by {
    assert(pre_self_.get_thread(t_ptr) =~= post1_self_.get_thread(t_ptr));
    assert(pre_self_.get_thread(t_ptr) =~= post2_self_.get_thread(t_ptr));
}

// --- Pointwise non-modified endpoints. ---
assert forall|e_ptr: EndpointPtr|
    #![trigger post1_self_.get_endpoint(e_ptr)]
    #![trigger post2_self_.get_endpoint(e_ptr)]
    post1_self_.endpoint_dom().contains(e_ptr) && e_ptr != ep_ptr
    implies post1_self_.get_endpoint(e_ptr) =~= post2_self_.get_endpoint(e_ptr) by {
    assert(post2_self_.endpoint_dom().contains(e_ptr));
    assert(pre_self_.get_endpoint(e_ptr) =~= post1_self_.get_endpoint(e_ptr));
    assert(pre_self_.get_endpoint(e_ptr) =~= post2_self_.get_endpoint(e_ptr));
}

// --- Modified thread: only the three pinned fields. ---
assert(post1_self_.get_thread(thread_ptr).endpoint_descriptors
        =~= pre_self_.get_thread(thread_ptr).endpoint_descriptors);
assert(post2_self_.get_thread(thread_ptr).endpoint_descriptors
        =~= pre_self_.get_thread(thread_ptr).endpoint_descriptors);
assert(post1_self_.get_thread(thread_ptr).endpoint_descriptors
        =~= post2_self_.get_thread(thread_ptr).endpoint_descriptors);

assert(post1_self_.get_thread(thread_ptr).ipc_payload =~= ipc_payload);
assert(post2_self_.get_thread(thread_ptr).ipc_payload =~= ipc_payload);
assert(post1_self_.get_thread(thread_ptr).ipc_payload
        =~= post2_self_.get_thread(thread_ptr).ipc_payload);

assert(post1_self_.get_thread(thread_ptr).state == ThreadState::BLOCKED);
assert(post2_self_.get_thread(thread_ptr).state == ThreadState::BLOCKED);
assert(post1_self_.get_thread(thread_ptr).state
        == post2_self_.get_thread(thread_ptr).state);

// --- Modified endpoint: only the three pinned fields. ---
assert(post1_self_.get_endpoint(ep_ptr).queue_state == queue_state);
assert(post2_self_.get_endpoint(ep_ptr).queue_state == queue_state);
assert(post1_self_.get_endpoint(ep_ptr).queue_state
        == post2_self_.get_endpoint(ep_ptr).queue_state);

assert(post1_self_.get_endpoint(ep_ptr).owning_threads
        == pre_self_.get_endpoint(ep_ptr).owning_threads);
assert(post2_self_.get_endpoint(ep_ptr).owning_threads
        == pre_self_.get_endpoint(ep_ptr).owning_threads);
assert(post1_self_.get_endpoint(ep_ptr).owning_threads
        == post2_self_.get_endpoint(ep_ptr).owning_threads);

assert(post1_self_.get_endpoint(ep_ptr).queue@
        == pre_self_.get_endpoint(ep_ptr).queue@.push(thread_ptr));
assert(post2_self_.get_endpoint(ep_ptr).queue@
        == pre_self_.get_endpoint(ep_ptr).queue@.push(thread_ptr));
assert(post1_self_.get_endpoint(ep_ptr).queue@
        =~= post2_self_.get_endpoint(ep_ptr).queue@);
